import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { useLocation } from 'react-router-dom';
import { navigateInAppPath } from '../router/navigateInAppPath';
import { reportTabId } from '../utils/reportDocumentDrillDown';
import type { OpenWorkspaceTabInput, WorkspaceTab } from './workspaceTabTypes';
import { titleFromPath } from './workspaceTabTypes';

type WorkspaceTabContextValue = {
  tabs: WorkspaceTab[];
  activeTabId: string | null;
  openWorkspaceTab: (input: OpenWorkspaceTabInput) => void;
  activateTab: (id: string) => void;
  closeTab: (id: string) => void;
};

const WorkspaceTabContext = createContext<WorkspaceTabContextValue | null>(null);

export type WorkspaceTabProviderProps = {
  children: React.ReactNode;
  navigate: (path: string) => void;
};

function pickFallbackTab(tabs: WorkspaceTab[], closedIndex: number): WorkspaceTab | undefined {
  const reportTab = tabs.find(t => t.tabKind === 'report');
  if (reportTab) return reportTab;
  return tabs[Math.max(0, closedIndex - 1)] ?? tabs[0];
}

function resolveOpenWorkspaceTab(
  prev: WorkspaceTab[],
  input: OpenWorkspaceTabInput,
): { tabs: WorkspaceTab[]; activeId: string } {
  let nextTabs = [...prev];

  if (input.returnPath) {
    const anchorId = reportTabId(input.returnPath);
    if (!nextTabs.some(t => t.id === anchorId)) {
      nextTabs.unshift({
        id: anchorId,
        path: input.returnPath,
        title: input.returnTitle ?? titleFromPath(input.returnPath),
        tabKind: 'report',
      });
    }
  }

  const reuse = input.reuseExisting !== false;
  if (reuse) {
    const existing = nextTabs.find(t => t.path === input.path);
    if (existing) {
      return { tabs: nextTabs, activeId: existing.id };
    }
  }

  if (input.documentType) {
    const typeIdx = nextTabs.findIndex(
      t => t.tabKind === 'document' && t.documentType === input.documentType,
    );
    if (typeIdx >= 0) {
      const tab = nextTabs[typeIdx];
      nextTabs = nextTabs.map((t, i) =>
        i === typeIdx ? { ...t, path: input.path, title: input.title } : t,
      );
      return { tabs: nextTabs, activeId: tab.id };
    }
  }

  const id = `tab-${crypto.randomUUID()}`;
  nextTabs.push({
    id,
    path: input.path,
    title: input.title,
    tabKind: 'document',
    documentType: input.documentType,
  });
  return { tabs: nextTabs, activeId: id };
}

export const WorkspaceTabProvider: React.FC<WorkspaceTabProviderProps> = ({
  children,
  navigate,
}) => {
  const location = useLocation();
  const [tabs, setTabs] = useState<WorkspaceTab[]>([]);
  const [activeTabId, setActiveTabId] = useState<string | null>(null);
  const tabsRef = useRef(tabs);
  tabsRef.current = tabs;
  const skipPathSyncRef = useRef(false);
  const returnPathRef = useRef<string | null>(null);

  useEffect(() => {
    if (!activeTabId || skipPathSyncRef.current) {
      skipPathSyncRef.current = false;
      return;
    }
    const path = location.pathname + location.search;
    setTabs(prev =>
      prev.map(t => (t.id === activeTabId ? { ...t, path } : t)),
    );
  }, [location.pathname, location.search, activeTabId]);

  const openWorkspaceTab = useCallback(
    (input: OpenWorkspaceTabInput) => {
      if (input.returnPath) {
        returnPathRef.current = input.returnPath;
      }

      const { tabs: nextTabs, activeId } = resolveOpenWorkspaceTab(tabsRef.current, input);
      tabsRef.current = nextTabs;
      setTabs(nextTabs);
      setActiveTabId(activeId);
      skipPathSyncRef.current = true;
      navigateInAppPath(input.path, navigate);
    },
    [navigate],
  );

  const activateTab = useCallback(
    (id: string) => {
      const tab = tabsRef.current.find(t => t.id === id);
      if (!tab) return;
      setActiveTabId(id);
      skipPathSyncRef.current = true;
      navigateInAppPath(tab.path, navigate);
    },
    [navigate],
  );

  const closeTab = useCallback(
    (id: string) => {
      const current = tabsRef.current;
      const idx = current.findIndex(t => t.id === id);
      if (idx < 0) return;
      const nextTabs = current.filter(t => t.id !== id);
      tabsRef.current = nextTabs;
      setTabs(nextTabs);

      if (nextTabs.length === 0) {
        setActiveTabId(null);
        const back = returnPathRef.current;
        if (back) {
          skipPathSyncRef.current = true;
          navigateInAppPath(back, navigate);
          returnPathRef.current = null;
        }
        return;
      }

      if (activeTabId !== id) return;
      const fallback = pickFallbackTab(nextTabs, idx);
      if (fallback) {
        setActiveTabId(fallback.id);
        skipPathSyncRef.current = true;
        navigateInAppPath(fallback.path, navigate);
      }
    },
    [activeTabId, navigate],
  );

  useEffect(() => {
    window.__LINM_OPEN_WORKSPACE_TAB__ = openWorkspaceTab;
    return () => {
      delete window.__LINM_OPEN_WORKSPACE_TAB__;
    };
  }, [openWorkspaceTab]);

  const value = useMemo(
    () => ({
      tabs,
      activeTabId,
      openWorkspaceTab,
      activateTab,
      closeTab,
    }),
    [tabs, activeTabId, openWorkspaceTab, activateTab, closeTab],
  );

  return (
    <WorkspaceTabContext.Provider value={value}>
      {children}
    </WorkspaceTabContext.Provider>
  );
};

export function useWorkspaceTabs(): WorkspaceTabContextValue {
  const ctx = useContext(WorkspaceTabContext);
  if (!ctx) {
    throw new Error('useWorkspaceTabs must be used within WorkspaceTabProvider');
  }
  return ctx;
}

/** Safe hook for optional tab bar (standalone without provider — should not happen). */
export function useWorkspaceTabsOptional(): WorkspaceTabContextValue | null {
  return useContext(WorkspaceTabContext);
}
