import { useCallback } from 'react';
import {
  useNavigate,
  type NavigateFunction,
  type NavigateOptions,
  type To,
} from 'react-router-dom';
import { navigateInAppPath } from './navigateInAppPath';

function resolveToPath(to: To): string | null {
  if (typeof to === 'string') return to;
  const pathname = to.pathname ?? '';
  const search = to.search ?? '';
  return `${pathname}${search}`;
}

/** Shell-safe `useNavigate` — updates URL bar in Root via `navigateInAppPath`. */
export function useInAppNavigate(): NavigateFunction {
  const navigate = useNavigate();
  const inAppNavigate = useCallback((to: To | number, options?: NavigateOptions) => {
    if (typeof to === 'number') {
      navigate(to);
      return;
    }
    const path = resolveToPath(to);
    if (!path) return;
    navigateInAppPath(path, navigate, options);
  }, [navigate]);
  return inAppNavigate as NavigateFunction;
}
